<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :key="loadKey" :viewerId="'viewer_' + loadKey" :parameter="parameter" :reportPath="reportPath">
                            </ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
        <ViewInvoiceLineItem v-if='isShowViewInvoiceLineItem' :columnId="columnId" :isProcessed="isProcessed" :lineItemId="lineItemId" :clientId="clientId"></ViewInvoiceLineItem>
    </section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
import {
    locateBillingService
} from "../../services/locateBillingService";
import moment from 'moment';
import ViewInvoiceLineItem from '../InvoiceReport/ViewInvoiceLineItem.vue';

export default {
    components: {
        ReportViewer,
        ViewInvoiceLineItem
    },
    data() {
        return {
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            isLoading: false,
            isShowViewInvoiceLineItem: false,
            reportPath: null,
            parameter: [],
            clientIds: '',
            LocationId: 0,
            currentReportParams: null,
            loadKey: 0,
            autoRunAttempted: false,
            columnId: '',
            isProcessed: '',
            lineItemId: '',
            clientId: [],
            DataLoaded: 0,
            urlParams: {
                cid: '',
                uid: '',
                did: '',
                sid: '',
                st: '',
                frq: '',
                wdf: '',
                wdt: '',
                pdf: '',
                pdt: '',
                wid: ''
            },
            FormSchema: [{
                    layoutType: "triple",
                    Data: [{
                            astype: "SearchableSelectField",
                            label: this.$t('CONTRACTNAME'),
                            name: "ContractName",
                            value: "",
                            placeholder: this.$t('SelectClient'),
                            visibility: true,
                            isSearch: true,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    active: true,
                                    inactive: true,
                                    clear: true
                                },
                                itemFields: ['text', 'status'],
                                isMultiple: true,
                                groupFields: ['groupText'],
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                                onChange: this.onSelectionChange
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('UtilityName'),
                            name: "UtilityName",
                            value: "",
                            placeholder: "Select Utility Name",
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                },
                                groupFields: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                                onChange: this.LoadDivisionList
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('Division'),
                            name: "Invoicegrouping",
                            value: "",
                            placeholder: "Select Division",
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                groupFields: ['groupText'],
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                },
                                groupFields: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [{
                            astype: "SelectField",
                            label: this.$t("Status"),
                            name: "Status",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Status'),
                            mode: "tag",
                            config: {
                                options: [{
                                    name: 'Billed Records',
                                    value: "1"
                                }, {
                                    name: 'Unbilled Records',
                                    value: "2"
                                }]
                            },
                            validationRules: {
                                "required": false
                            }
                        },
                        {
                            astype: "DateRangeField",
                            label: this.$t('Work_Date'),
                            name: "WorkDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: false,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("State"),
                            name: "State",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('State'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                isMultiple: false,
                                groupFields: [],
                                minSearchLength: 0,
                                actionButtons: {
                                    clear: true
                                },
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                }
                            },
                            validationRules: {
                                required: false
                            }
                        }
                    ]
                },
                {
                    layoutType: "triple",
                    Data: [{
                            astype: "SelectField",
                            label: this.$t("Frequency"),
                            name: "Frequency",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Status'),
                            mode: "tag",
                            config: {
                                options: [{
                                    name: 'Annually',
                                    value: "annual"
                                }, {
                                    name: 'Bi-Weekly',
                                    value: "biweek"
                                }, {
                                    name: 'Custom Date',
                                    value: "custom"
                                }, {
                                    name: 'Daily',
                                    value: "daily"
                                }, {
                                    name: 'Half yearly',
                                    value: "halfyear"
                                }, {
                                    name: 'Monthly',
                                    value: "month"
                                }, {
                                    name: 'Quarterly',
                                    value: "quarterly"
                                }, {
                                    name: 'Weekly',
                                    value: "week"
                                }]
                            },
                            validationRules: {
                                "required": false
                            }
                        },
                        {
                            astype: "DateRangeField",
                            label: this.$t('Proccess Date'),
                            name: "ProccessDateFrom",
                            value: "",
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                maxDate: false,
                                onChange: this.setTimerDate,
                                datePickerConfig: {
                                    useCurrent: true,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                                secondDatePickerConfig: {
                                    useCurrent: false,
                                    showClear: true,
                                    showClose: true,
                                    allowInputToggle: false,
                                    minDate: true,
                                    maxDate: true,
                                    widgetPositioning: {
                                        horizontal: 'right',
                                        vertical: 'bottom'
                                    }
                                },
                            },
                            validationRules: {
                                "required": false
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t("Work Code"),
                            name: "Workcode",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Work Code'),
                            visibility: true,
                            isSearch: true,
                            config: {
                                options: [],
                                groupFields: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                actionButtons: {
                                    selectAll: true,
                                    clear: true
                                }
                            },
                            validationRules: {
                                required: false
                            }
                        }
                    ]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.parseUrlParameters();
        vm.DataLoaded = 1;
    },
    mounted() {
        this.$nextTick(() => {
            this.initializePage();
        });
        window.handleExceededLink = () => {
            this.saveReportRequest();
        };
        window.handleViewLineItem = (columnId, isProcessed, lineItemId, clientId) => {
            this.openLineItemDetails(columnId, isProcessed, lineItemId, clientId);
        };
    },
    beforeDestroy() {
        delete window.handleExceededLink;
        delete window.handleViewLineItem;
    },
    methods: {
        parseUrlParameters() {
            const vm = this;
            const query = vm.$route.query;
            vm.urlParams = {
                cid: query.cid || '',
                uid: query.uid || '',
                did: query.did || '',
                sid: query.sid || '',
                st: query.st || '',
                frq: query.frq || '',
                wdf: query.wdf || '',
                wdt: query.wdt || '',
                pdf: query.pdf || '',
                pdt: query.pdt || '',
                wid: query.wid || ''
            };
        },
        async initializePage() {
            const vm = this;
            vm.isLoading = true;

            try {
                await Promise.all([
                    vm.fetchclientlist(),
                    vm.GetDDLStateList(),
                    vm.GetWorkCodeInfo()
                ]);

                await vm.waitForFormComponent();

                await vm.setFormValuesFromUrl();

                await new Promise(resolve => setTimeout(resolve, 500));

                await vm.autoRunReport();

            } catch (error) {
                console.error('Error initializing page:', error);
                vm.ShowAlert("Error loading form: " + error.message, "failure", true, vm.$t("Alert"));
            } finally {
                vm.isLoading = false;
            }
        },
        waitForFormComponent() {
            return new Promise((resolve, reject) => {
                const maxAttempts = 20;
                let attempts = 0;

                const checkForm = () => {
                    attempts++;
                    if (this.$refs.BarcodeReport) {
                        console.log('Form component found on attempt', attempts);
                        resolve();
                    } else if (attempts >= maxAttempts) {
                        reject(new Error('Form component not found after ' + maxAttempts + ' attempts'));
                    } else {
                        setTimeout(checkForm, 100);
                    }
                };

                checkForm();
            });
        },
        async setFormValuesFromUrl() {
            const vm = this;
            
            const convertDateFormat = (dateStr) => {
                if (!dateStr || dateStr === '0001-01-01' || dateStr === '') return '';
                try {
                    return moment(dateStr, 'YYYY-MM-DD').format('MM/DD/YYYY');
                } catch (e) {
                    console.error('Error converting date:', dateStr, e);
                    return '';
                }
            };

            if (vm.urlParams.cid && vm.urlParams.cid !== '') {
                const clientIds = vm.urlParams.cid.split(',').filter(id => id.trim() !== '');
                const selectedClients = [];

                clientIds.forEach(clientId => {
                    const clientOption = vm.FormSchema[0].Data[0].config.options.find(opt =>
                        opt.value.toString() === clientId.toString().trim()
                    );
                    if (clientOption) {
                        selectedClients.push(clientOption);
                    } else {
                        console.warn('Client not found in options:', clientId);
                    }
                });

                if (selectedClients.length > 0) {
                    vm.FormSchema[0].Data[0].value = selectedClients.map(item => item.value);
                    vm.clientIds = selectedClients.map(item => item.value).join(",");
                    
                    await vm.onSelectionChange(null, selectedClients.map(item => item.value));
                }
            }

            if (vm.urlParams.sid && vm.urlParams.sid !== '') {
                vm.FormSchema[1].Data[0].value = vm.urlParams.sid.toString();
            }

            if (vm.urlParams.wdf && vm.urlParams.wdf !== '') {
                const formattedDate = convertDateFormat(vm.urlParams.wdf);
                if (formattedDate) {
                    vm.FormSchema[1].Data[1].value = formattedDate;
                }
            }

            if (vm.urlParams.wdt && vm.urlParams.wdt !== '') {
                const formattedDate = convertDateFormat(vm.urlParams.wdt);
                if (formattedDate) {
                    vm.FormSchema[1].Data[1].secondValue = formattedDate;
                }
            }

            if (vm.urlParams.st && vm.urlParams.st !== '') {
                vm.FormSchema[1].Data[2].value = vm.urlParams.st.toString();
            }

            if (vm.urlParams.frq && vm.urlParams.frq !== '') {
                vm.FormSchema[2].Data[0].value = vm.urlParams.frq;
            }

            if (vm.urlParams.pdf && vm.urlParams.pdf !== '' && vm.urlParams.pdf !== '0001-01-01') {
                const formattedDate = convertDateFormat(vm.urlParams.pdf);
                if (formattedDate) {
                    vm.FormSchema[2].Data[1].value = formattedDate;
                }
            }

            if (vm.urlParams.pdt && vm.urlParams.pdt !== '' && vm.urlParams.pdt !== '0001-01-01') {
                const formattedDate = convertDateFormat(vm.urlParams.pdt);
                if (formattedDate) {
                    vm.FormSchema[2].Data[1].secondValue = formattedDate;
                }
            }

            if (vm.urlParams.wid && vm.urlParams.wid !== '') {
                const workCodeIds = vm.urlParams.wid.split(',').filter(id => id.trim() !== '');
                const selectedWorkCodes = [];

                workCodeIds.forEach(workCodeId => {
                    const workCodeOption = vm.FormSchema[2].Data[2].config.options.find(opt =>
                        opt.value.toString() === workCodeId.toString().trim()
                    );
                    if (workCodeOption) {
                        selectedWorkCodes.push(workCodeOption.value);
                    }
                });

                if (selectedWorkCodes.length > 0) {
                    vm.FormSchema[2].Data[2].value = selectedWorkCodes;
                }
            }

            if (vm.urlParams.uid && vm.urlParams.uid !== '') {
                const utilityIds = vm.urlParams.uid.split(',').filter(id => id.trim() !== '');
                vm.FormSchema[0].Data[1].value = utilityIds;
            }

            if (vm.urlParams.did && vm.urlParams.did !== '') {
                const divisionIds = vm.urlParams.did.split(',').filter(id => id.trim() !== '');
                vm.FormSchema[0].Data[2].value = divisionIds;
            }

            if (vm.$refs.BarcodeReport) {
                await vm.$nextTick();
                vm.$refs.BarcodeReport.UpdateKeyValue();
            }
        },
        getCurrentFormData() {
            const vm = this;
            const formData = {};

            vm.FormSchema.forEach(section => {
                section.Data.forEach(field => {
                    formData[field.name] = field.value;
                });
            });

            return formData;
        },
        async autoRunReport() {
            const vm = this;

            if (vm.autoRunAttempted) return;
            vm.autoRunAttempted = true;

            console.log('Auto-running report...');

            await vm.$nextTick();

            if (!vm.$refs.BarcodeReport) {
                console.error('Form component not found for auto-run');
                return;
            }

            try {
                const formData = vm.getCurrentFormData();
                console.log('Form data for auto-run:', formData);
                if (!formData || !formData.Status) {
                    console.log('Required data (Status) not available for auto-running report');
                    return;
                }
                await vm.onSubmit(formData);
            } catch (error) {
                console.error('Error auto-running report:', error);
            }
        },
        setTimerDate: function (selectedDate, field, isSecondPicker = false) {
            const vm = this;

            const rangeFieldName = field.name;
            let startVal = vm.$refs.BarcodeReport?.getPropertyValue(rangeFieldName, "value") || null;
            let endVal = vm.$refs.BarcodeReport?.getPropertyValue(rangeFieldName, "secondValue") || null;

            const toMoment = (val) => val ? moment(val, "MM/DD/YYYY", true) : null;

            let start = toMoment(startVal);
            let end = toMoment(endVal);
            const today = moment().startOf('day');

            if (start?.isValid()) {
                vm.$refs.BarcodeReport.updateProperty(
                    rangeFieldName,
                    "config.secondDatePickerConfig.minDate",
                    start.format("MM/DD/YYYY")
                );
            } else {
                vm.$refs.BarcodeReport.updateProperty(
                    rangeFieldName,
                    "config.secondDatePickerConfig.minDate",
                    false
                );
            }

            if (end?.isValid()) {
                vm.$refs.BarcodeReport.updateProperty(
                    rangeFieldName,
                    "config.datePickerConfig.maxDate",
                    end.format("MM/DD/YYYY")
                );
            } else {
                vm.$refs.BarcodeReport.updateProperty(
                    rangeFieldName,
                    "config.datePickerConfig.maxDate",
                    false
                );
            }

            if (!isSecondPicker) {
                if (start?.isValid()) {
                    if (!end?.isValid()) {
                        const newEnd = today.format("MM/DD/YYYY");
                        vm.$refs.BarcodeReport.updateProperty(rangeFieldName, "secondValue", newEnd);
                    } else if (end.isBefore(start)) {
                        const newEnd = start.format("MM/DD/YYYY");
                        vm.$refs.BarcodeReport.updateProperty(rangeFieldName, "secondValue", newEnd);
                    }
                }
            }

            if (isSecondPicker) {
                if (end?.isValid()) {
                    if (!start?.isValid()) {
                        const newStart = end.isAfter(today) ? today.format("MM/DD/YYYY") : end.format("MM/DD/YYYY");
                        vm.$refs.BarcodeReport.updateProperty(rangeFieldName, "value", newStart);
                    } else if (start.isAfter(end)) {
                        const newStart = end.format("MM/DD/YYYY");
                        vm.$refs.BarcodeReport.updateProperty(rangeFieldName, "value", newStart);
                    }
                }
            }
            vm.$refs.BarcodeReport?.UpdateKeyValue();
        },
        async onSubmit(e) {
            var vm = this;
            vm.isLoading = true;
            vm.loadKey = Date.now();
            vm.reportPath = '';
            vm.parameter = [];
            
            vm.WorkDateFrom = vm.$refs.BarcodeReport.getPropertyValue("WorkDateFrom", "value");
            vm.WorkDateTo = vm.$refs.BarcodeReport.getPropertyValue("WorkDateFrom", "secondValue");
            vm.ProccessDateFrom = vm.$refs.BarcodeReport.getPropertyValue("ProccessDateFrom", "value");
            vm.ProccessDateTo = vm.$refs.BarcodeReport.getPropertyValue("ProccessDateFrom", "secondValue");
            
            const extractValues = (fieldValue) => {
                if (!fieldValue) return '';
                if (Array.isArray(fieldValue)) {
                    return fieldValue.join(",");
                }
                return fieldValue;
            };
            
            let myObj = {
                reportName: "billedunbilledreport",
                ClientIds: extractValues(e.ContractName),
                dateFrom: vm.formatDate(vm.WorkDateFrom),
                dateTo: vm.formatDate(vm.WorkDateTo),
                ProccessFromDate: vm.formatDate(vm.ProccessDateFrom),
                ProccessToDate: vm.formatDate(vm.ProccessDateTo),
                DivisionId: extractValues(e.Invoicegrouping),
                State: e.State,
                Status: e.Status,
                Frequency: e.Frequency,
                UtilityIds: extractValues(e.UtilityName),
                Workcode: extractValues(e.Workcode)
            };
            
            vm.currentReportParams = myObj;
            
            var postString = JSON.stringify(myObj);
            
            try {
                let response = await DataServices.ReportMain(postString);
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
            } catch (error) {
                console.error("Error loading report:", error);
            } finally {
                vm.isLoading = false;
            }
        },
        formatDate(value) {
            if (!value) return null;
            try {
                return moment(value).format('MM-DD-YYYY');
            } catch (e) {
                console.error('Error formatting date:', value, e);
                return null;
            }
        },
        ClearAll: function () {
            var vm = this;
            vm.FormSchema[0].Data[1].config.options = [];
            vm.FormSchema[0].Data[2].config.options = [];
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[1].value = '';
            (vm.FormSchema)[1].Data[1].secondValue = '';
            (vm.FormSchema)[1].Data[2].value = '';
            (vm.FormSchema)[2].Data[0].value = '';
            (vm.FormSchema)[2].Data[1].value = '';
            (vm.FormSchema)[2].Data[1].secondValue = '';
            (vm.FormSchema)[2].Data[2].value = '';
            vm.clientId = [];
            vm.reportPath = '';
            vm.parameter = [];
            vm.loadKey = 0;
            vm.currentReportParams = null;
            vm.autoRunAttempted = false;
            if (vm.$refs.BarcodeReport && vm.$refs.BarcodeReport.validateForm) {
                vm.$refs.BarcodeReport.validateForm.reset();
            }
        },
        async fetchclientlist() {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOMREPORT`;
            try {
                let response = await locateBillingService.getClientList(url);
                vm.ClientData = response.data.items;
                vm.FormSchema[0].Data[0].config.options = vm.ClientData;
                if (vm.$refs.BarcodeReport) {
                    vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", vm.ClientData);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                vm.ClientData = [];
                vm.FormSchema[0].Data[0].config.options = [];
                if (vm.$refs.BarcodeReport) {
                    vm.$refs.BarcodeReport.updateProperty("ContractName", "config.options", vm.ClientData);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
                console.error('Error fetching client list:', error);
            } finally {
                vm.isLoading = false;
            }
        },
        async onSelectionChange(value, selectedClientIds) {
            var vm = this;
            vm.isLoading = true;
            
            if (selectedClientIds && selectedClientIds.length > 0) {
                vm.selectedClientId = selectedClientIds;
                vm.clientId = selectedClientIds;
                vm.clientIds = selectedClientIds.join(",");
            } else {
                vm.selectedClientId = null;
                vm.clientId = null;
                vm.clientIds = '';
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "value", '');
                vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "config.options", []);
                vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "value", '');
                vm.isLoading = false;
                return;
            }
            
            var url = `clientId=${vm.selectedClientId}&configId=&reqFrom=&clientIds=${vm.clientIds}`;
            
            try {
                let response = await locateBillingService.getUtilityList(url);
                let SelectedUtilityList = [];
                var UtilityList = response.data;
                
                if (UtilityList != null && UtilityList.length > 0) {
                    UtilityList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.UTILITY_NAME,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.UTILITY_NAME,
                            value: item.UTILITY_ID
                        };
                        SelectedUtilityList.push(obj);
                    });
                    
                    vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", SelectedUtilityList);
                    
                    if (vm.urlParams.uid && vm.urlParams.uid !== '') {
                        const utilityIds = vm.urlParams.uid.split(',').filter(id => id.trim() !== '');
                        vm.$refs.BarcodeReport.updateProperty("UtilityName", "value", utilityIds);
                        
                        await vm.LoadDivisionList(null, utilityIds);
                    }
                    
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                vm.isLoading = false;
                vm.UtilityList = [];
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "config.options", []);
                vm.$refs.BarcodeReport.updateProperty("UtilityName", "value", '');
                console.error('Error loading utilities:', error);
            } finally {
                vm.isLoading = false;
            }
        },
        async LoadDivisionList(value, selectedUtilityIds) {
            var vm = this;
            vm.isLoading = true;
            
            var selectedUtilityIdsStr = selectedUtilityIds ? selectedUtilityIds.join(',') : '';
            var clientIdsStr = vm.clientId ? vm.clientId.join(',') : '';
            
            if (!clientIdsStr || !selectedUtilityIdsStr) {
                vm.isLoading = false;
                vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "config.options", []);
                vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "value", "");
                vm.$refs.BarcodeReport.UpdateKeyValue();
                return;
            }
            
            var url = `ClientId=${clientIdsStr}&UtilityIds=${selectedUtilityIdsStr}`;
            
            try {
                let response = await DataServices.GetInvoiceGrouping(url);
                let SelectedDivisionList = [];
                
                if (response.data && response.data.length > 0) {
                    response.data.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.NOTE,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.NOTE,
                            value: item.ID
                        };
                        SelectedDivisionList.push(obj);
                    });
                }
                
                if (vm.$refs.BarcodeReport) {
                    vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "config.options", SelectedDivisionList);
                    
                    if (vm.urlParams.did && vm.urlParams.did !== '') {
                        const divisionIds = vm.urlParams.did.split(',').filter(id => id.trim() !== '');
                        vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "value", divisionIds);
                    }
                    
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } catch (error) {
                console.error('Error loading divisions:', error);
                if (vm.$refs.BarcodeReport) {
                    vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "config.options", []);
                    vm.$refs.BarcodeReport.updateProperty("Invoicegrouping", "value", "");
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } finally {
                vm.isLoading = false;
            }
        },
        async GetDDLStateList() {
            var vm = this;
            vm.isLoading = true;
            var params = `CountryId=223&InclueCandaState=true`;
            try {
                let response = await DataServices.GetDDLStateList(params);
                let SelectedStateList = [];
                if (response.data && response.data.length > 0) {
                    var StateData = response.data;
                    StateData.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.STATE_NAME + '(' + item.ISO_CODE_3 + ')',
                            value: item.ISO_CODE_3
                        };
                        SelectedStateList.push(obj);
                    });
                    if (vm.$refs.BarcodeReport) {
                        vm.$refs.BarcodeReport.updateProperty("State", "config.options", SelectedStateList);
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                }
            } catch (error) {
                console.error('Error fetching states:', error);
                if (vm.$refs.BarcodeReport) {
                    vm.$refs.BarcodeReport.updateProperty("State", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } finally {
                vm.isLoading = false;
            }
        },
        async GetWorkCodeInfo() {
            var vm = this;
            vm.isLoading = true;
            try {
                let response = await DataServices.GetWorkCodeInfo();
                let SelectedWorkCodeList = [];
                if (response.data && response.data.length > 0) {
                    var WorkCodeData = response.data;
                    WorkCodeData.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.work_code,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.work_code,
                            value: item.work_code_id
                        };
                        SelectedWorkCodeList.push(obj);
                    });
                    if (vm.$refs.BarcodeReport) {
                        vm.$refs.BarcodeReport.updateProperty("Workcode", "config.options", SelectedWorkCodeList);
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                }
            } catch (error) {
                console.error('Error fetching work codes:', error);
                if (vm.$refs.BarcodeReport) {
                    vm.$refs.BarcodeReport.updateProperty("Workcode", "config.options", []);
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            } finally {
                vm.isLoading = false;
            }
        },
        openLineItemDetails(columnId, isProcessed, lineItemId, clientId) {
            var vm = this;
            vm.columnId = columnId;
            vm.isProcessed = isProcessed;
            vm.lineItemId = lineItemId;
            vm.clientId = clientId;
            vm.isShowViewInvoiceLineItem = true;
        },
        async saveReportRequest() {
            var vm = this;
            vm.isLoading = true;
            try {
                if (!vm.currentReportParams) {
                    console.error('No report parameters available. Please generate a report first.');
                    return;
                }

                const params = {
                    reportName: vm.currentReportParams.reportName || 'billedunbilledreport',
                    hdnClientId: vm.currentReportParams.ClientIds || '',
                    startDate: vm.currentReportParams.dateFrom || '',
                    endDate: vm.currentReportParams.dateTo || '',
                    DivisionInvoiceFrequency: vm.currentReportParams.Frequency || '',
                    hdnStatusId: vm.currentReportParams.Status || '',
                    hdnState: vm.currentReportParams.State || '',
                    UtilityNames: vm.currentReportParams.UtilityName || '',
                    DivisionNames: vm.currentReportParams.Invoicegrouping || '',
                    ProcessFromDate: vm.currentReportParams.ProccessFromDate || '',
                    ProcessToDate: vm.currentReportParams.ProccessToDate || '',
                    Workcode: vm.currentReportParams.Workcode || ''
                };

                console.log('Saving report request with params:', params);

                let response = await DataServices.SaveReportRequest(params);
                if (response.data && response.data.result === 'success') {
                    vm.ShowAlert("Request submitted successfully", "success", true, vm.$t("Alert"));
                } else {
                    vm.ShowAlert("We couldn't submit your request. Please try again.", "failure", true, vm.$t("Alert"));
                }
            } catch (error) {
                console.error('Error saving report request:', error);
            } finally {
                vm.isLoading = false;
            }
        }
    }
};
</script>